const item = $input.first()?.json ?? {};
const body = item.body ?? item;

if (body.event !== 'message_created') {
  return [];
}

const isIncoming = body.message_type === 'incoming' || body.message_type === 0;
if (!isIncoming) {
  return [];
}

const conversationId = body.conversation?.id;
if (!conversationId) {
  return [];
}

const content = (body.content ?? '').toString().trim();
if (!content) {
  return [];
}

const senderName =
  (body.sender?.name ?? 'prospect').toString().trim() || 'prospect';

const fallbackReply =
  "Bonjour et merci pour votre message. Pour bien vous orienter, pouvez-vous me preciser le nom de votre entreprise, votre secteur d'activite et votre besoin principal ?";

return [
  {
    json: {
      conversation_id: conversationId,
      incoming_text: content,
      sender_name: senderName,
      fallback_reply: fallbackReply
    }
  }
];

const context = $('Filter Chatwoot event').first()?.json ?? {};
const historyResponse = $input.first()?.json ?? {};

const payload =
  historyResponse.payload ??
  historyResponse.data ??
  historyResponse.messages ??
  historyResponse;

const rawMessages = Array.isArray(payload) ? payload : [];

const MAX_HISTORY = 20;

const normalizedHistory = rawMessages
  .map((msg) => {
    const text = (msg.content ?? msg.processed_message_content ?? '')
      .toString()
      .trim();
    if (!text) return null;

    const isAssistant =
      msg.message_type === 1 || msg.message_type === 'outgoing';

    return {
      role: isAssistant ? 'assistant' : 'user',
      content: text
    };
  })
  .filter(Boolean)
  .slice(-MAX_HISTORY);

const currentText = (context.incoming_text ?? '').toString().trim();
const lastUserInHistory =
  [...normalizedHistory].reverse().find((m) => m.role === 'user')?.content ?? '';

const alreadyIncluded = lastUserInHistory === currentText;

const systemPrompt = [
  "Tu es l'assistant commercial de TransferAI Africa.",
  "Tu reponds exclusivement en francais, de facon claire, courte et professionnelle.",
  "Tu exploites l'historique de conversation pour ne pas redemander les informations deja fournies.",
  "Tu accueilles chaleureusement le prospect, reformules son besoin si utile, puis poses au maximum 3 questions de qualification si des informations manquent encore.",
  "Tu aides surtout les organisations en Afrique sur la formation IA, la veille strategique et l'automatisation.",
  "Si le besoin parait serieux et B2B, tu peux proposer une demo ou un echange avec l'equipe.",
  "Ne promets jamais un prix, un delai ou un resultat non confirme.",
  "Reste concret, poli et utile."
].join(' ');

const messages = [
  { role: 'system', content: systemPrompt },
  ...normalizedHistory
];

if (!alreadyIncluded && currentText) {
  messages.push({ role: 'user', content: currentText });
}

return [
  {
    json: {
      conversation_id: context.conversation_id,
      incoming_text: context.incoming_text,
      sender_name: context.sender_name,
      fallback_reply: context.fallback_reply,
      history_count: normalizedHistory.length,
      already_included: alreadyIncluded,
      openai_payload: {
        model: 'gpt-4.1-mini',
        temperature: 0.4,
        max_tokens: 350,
        messages
      }
    }
  }
];

const context = $('Build OpenAI payload with history').first()?.json ?? {};
const openai = $input.first()?.json ?? {};

const aiText = openai.choices?.[0]?.message?.content?.toString().trim();
const replyText = aiText || context.fallback_reply;

return [
  {
    json: {
      conversation_id: context.conversation_id,
      incoming_text: context.incoming_text,
      reply_text: replyText,
      used_fallback: !aiText,
      history_count: context.history_count,
      already_included: context.already_included
    }
  }
];
